SELECT bs_per_bldg.comstock_building_type, sum(bs_per_bldg.tract_count) AS sample_count, sum(bs_per_bldg.bldg_weight) AS units_count, sum(ts_aggr._inner_rows) / CAST(count(DISTINCT (ts_aggr.bldg_id, ts_aggr.state)) AS DECIMAL) AS rows_per_sample, sum(ts_aggr."bs__out.electricity.total.energy_consumption" * bs_per_bldg.bldg_weight) AS "electricity.total.energy_consumption" FROM (SELECT ts_flat.state AS state, ts_flat.bldg_id AS bldg_id, sum(ts_flat."_v__out.electricity.total.energy_consumption") AS "bs__out.electricity.total.energy_consumption", count(*) AS _inner_rows FROM (SELECT comstock_amy2018_r2_2025_ts_by_state.state AS state, comstock_amy2018_r2_2025_ts_by_state.bldg_id AS bldg_id, comstock_amy2018_r2_2025_ts_by_state."out.electricity.total.energy_consumption" AS "_v__out.electricity.total.energy_consumption" FROM comstock_amy2018_r2_2025_ts_by_state WHERE comstock_amy2018_r2_2025_ts_by_state.upgrade IN (0) AND comstock_amy2018_r2_2025_ts_by_state.state = 'CO') AS ts_flat GROUP BY ts_flat.state, ts_flat.bldg_id) AS ts_aggr JOIN (SELECT bs.bldg_id AS bldg_id, bs.state AS state, bs."in.comstock_building_type" AS comstock_building_type, sum(bs.weight) AS bldg_weight, count(*) AS tract_count FROM comstock_amy2018_r2_2025_md_by_state_and_county_parquet AS bs WHERE bs.upgrade = 0 AND bs.state = 'CO' GROUP BY bs.bldg_id, bs.state, bs."in.comstock_building_type") AS bs_per_bldg ON bs_per_bldg.bldg_id = ts_aggr.bldg_id AND bs_per_bldg.state = ts_aggr.state GROUP BY 1 ORDER BY 1